def test_mobile_cheque_deposit_unauthorised_returns_401(valid_cheque_image):
    no_auth_headers = {"Content-Type": "application/json"}
    payload = {
        "amount": 500.00,
        "currency": "USD",
        "image_b64": valid_cheque_image
    }
    resp = <api_client>.post("/deposits/mobile-cheque", json=payload, headers=no_auth_headers)
    assert resp.status_code == 401
    body = resp.json()
    assert body["error"]["code"] in ("UNAUTHORIZED", "INVALID_TOKEN")
    assert "deposit_id" not in body
